def is_valid_email(email):
    if '@' not in email:
        return False
    if '.' not in email:
        return False
    at_pos = email.find('@')
    dot_pos = email.rfind('.')
    if at_pos == 0 or at_pos == len(email) - 1:
        return False
    if dot_pos <= at_pos + 1 or dot_pos == len(email) - 1:
        return False
    return True

