import time
class APICache:
    def __init__(self, ttl=60):
        self.cache = {}
        self.ttl = ttl
    def set(self, endpoint, params, response):
        if endpoint not in self.cache:
            self.cache[endpoint] = {}
        self.cache[endpoint][str(params)] = (response, time.time())
    def get(self, endpoint, params):
        if endpoint in self.cache and str(params) in self.cache[endpoint]:
            response, timestamp = self.cache[endpoint][str(params)]
            if time.time() - timestamp < self.ttl:
                return response
        return None

